-        }
-        checkCudaErrors(cudaEventRecord(stop, 0));
-        checkCudaErrors(cudaDeviceSynchronize());
-        checkCudaErrors(cudaEventElapsedTime(&elapsedTimeInMs, start, stop));
-        if (bDontUseGPUTiming) {
