-    printLastCudaError("cudaD3D9GetDevice failed");  // This prints and resets
-                                                     // the cudaError to
-                                                     // cudaSuccess
-
-    printf("> Display Device #%d: \"%s\" %s Direct3D9\n", g_iAdapter,
-           adapterId.Description,
