-void initParticles(cData *p, int dx, int dy) {
-  int i, j;
-
-  for (i = 0; i < dy; i++) {
-    for (j = 0; j < dx; j++) {
-      p[i * dx + j].x = (j + 0.5f + (myrand() - 0.5f)) / dx;
-      p[i * dx + j].y = (i + 0.5f + (myrand() - 0.5f)) / dy;
-    }
-  }
-}
